import React, { useState, useEffect } from "react";

const StudyRoom = ({ task, onComplete }) => {
    const [seconds, setSeconds] = useState(0);
    const [isIdle, setIsIdle] = useState(false);
    const [lastMove, setLastMove] = useState(Date.now());
    const [showQuiz, setShowQuiz] = useState(false);

    useEffect(() => {
        // Track Mouse Movement
        const handleMouseMove = () => {
            setLastMove(Date.now());
            setIsIdle(false);
        };
        window.addEventListener("mousemove", handleMouseMove);

        const interval = setInterval(() => {
            setSeconds(prev => {
                // Trigger AI Quiz every 5 minutes (300 seconds)
                if (prev > 0 && prev % 300 === 0) {
                    setShowQuiz(true);
                }
                return prev + 1;
            });

            // Check for 2 minutes of inactivity (120000ms)
            if (Date.now() - lastMove > 120000) {
                setIsIdle(true);
            }
        }, 1000);

        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            clearInterval(interval);
        };
    }, [lastMove]);

    return (
        <div className="p-6 border rounded-lg shadow-md bg-white">
            <h2 className="text-xl font-bold mb-4">Focusing on: {task.title}</h2>
            <div className="text-3xl font-mono mb-4">
                Timer: {Math.floor(seconds / 60)}:{(seconds % 60).toString().padStart(2, '0')}
            </div>

            {isIdle && (
                <div className="text-red-500 font-bold animate-bounce">
                    Warning: Inactivity detected! Please stay focused.
                </div>
            )}

            {showQuiz && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center">
                    <div className="bg-white p-8 rounded shadow-xl text-center">
                        <h3 className="text-lg font-bold mb-4">AI Verification Quiz</h3>
                        <p className="mb-4">Briefly explain the concept of "{task.title}" to continue.</p>
                        <textarea className="w-full border p-2 mb-4" placeholder="Your answer..."></textarea>
                        <button 
                            onClick={() => setShowQuiz(false)}
                            className="bg-blue-600 text-white px-4 py-2 rounded"
                        >
                            Submit Answer
                        </button>
                    </div>
                </div>
            )}

            <button 
                onClick={() => onComplete(task._id)}
                className="mt-6 bg-green-600 text-white px-6 py-2 rounded hover:bg-green-700"
            >
                Mark as Completed
            </button>
        </div>
    );
};

export default StudyRoom;
